 {"id":"002","title":"Sovereign Procurement Trust Room","subtitle":"A procurement-ready trust room for buyer due diligence.","url":"proof-card-002.html","focus":"Enterprise trust","agialpha":"coordinates proof mission, builder, reviewer, credential, reputation","rsi":"turns validated due-diligence answers into reusable trust artifacts"},
 {"id":"003","title":"Sovereign AI Procurement Control Tower","subtitle":"Control-plane proof for AI adoption, governance, review, rollback, and auditability.","url":"proof-card-003.html","focus":"Institutional control","agialpha":"coordinates proof-settled governance work and evidence routing","rsi":"accepted procurement control artifacts improve future procurement workflows"},
